patch:
--- a/multiplier.sv
+++ b/multiplier.sv
@@ -1,11 +1,11 @@
 module multiplier_8bit(
   input wire [7:0] data_a,
   input wire [7:0] data_b,
   output wire [15:0] product
 );
   assign product = data_a * data_b;
 endmodule

 module processor;
   wire [7:0] val1, val2;
-  wire [15:0] res;
-  multiplier_8bit mult (.data_a(val1), .data_b(val2[7:0]), .product(res[14:0]));
+  wire [15:0] res;
+  multiplier_8bit mult (.data_a(val1), .data_b(val2), .product(res));
 endmodule

before_code:
module multiplier_8bit(
  input wire [7:0] data_a,
  input wire [7:0] data_b,
  output wire [15:0] product
);
  assign product = data_a * data_b;
endmodule

module processor;
  wire [7:0] val1, val2;
  wire [15:0] res;
  multiplier_8bit mult (.data_a(val1), .data_b(val2[7:0]), .product(res[14:0]));
endmodule

after_code:
module multiplier_8bit(
  input wire [7:0] data_a,
  input wire [7:0] data_b,
  output wire [15:0] product
);
  assign product = data_a * data_b;
endmodule

module processor;
  wire [7:0] val1, val2;
  wire [15:0] res;
  multiplier_8bit mult (.data_a(val1), .data_b(val2), .product(res));
endmodule
